/**
 * Tier 2.5: TUI Integration Tests with @microsoft/tui-test
 *
 * @microsoft/tui-test provides high-level TUI testing that bridges
 * the gap between component tests (Tier 2) and full PTY tests (Tier 3).
 * It can test the actual CLI in a controlled terminal environment.
 *
 * This tier validates that Tier 2's mocked components match real behavior
 * before Tier 3's full PTY testing.
 */

import { describe, it, expect } from 'vitest';
import { tuiTest, KEYS } from '@microsoft/tui-test';
import * as path from 'path';

const CLI_PATH = path.join(process.cwd(), 'dist', 'cli.js');

describe('Tier 2.5: TUI Integration (@microsoft/tui-test)', () => {
  describe('Initial Render', () => {
    it('should display welcome message on startup', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);

        // Wait for the welcome message
        await session.waitForText('Welcome to chipilot');

        // Verify header elements
        expect(await session.hasText('chipilot')).toBe(true);
        expect(await session.hasText('Agentic EDA')).toBe(true);
      });
    }, 10000);

    it('should show help hint in header', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome to chipilot');

        expect(await session.hasText('Tab: switch')).toBe(true);
        expect(await session.hasText('Ctrl+C: exit')).toBe(true);
        expect(await session.hasText('?: help')).toBe(true);
      });
    }, 10000);
  });

  describe('Input Handling', () => {
    it('should accept and display typed input', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        // Type some text
        await session.type('hello world');

        // Verify text appears
        expect(await session.hasText('hello world')).toBe(true);
      });
    }, 10000);

    it('should handle backspace', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        await session.type('helo');
        await session.keyPress(KEYS.BACKSPACE);
        await session.type('lo');

        expect(await session.hasText('hello')).toBe(true);
      });
    }, 10000);
  });

  describe('Pane Switching', () => {
    it('should switch to terminal pane with Tab', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        // Press Tab to switch panes
        await session.keyPress(KEYS.TAB);

        // Should show terminal-focused UI
        await session.waitForText('Tab to return to chat');
        expect(await session.hasText('Terminal')).toBe(true);
      });
    }, 10000);

    it('should preserve input when switching panes', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        // Type in chat pane
        await session.type('preserved message');
        expect(await session.hasText('preserved message')).toBe(true);

        // Switch to terminal
        await session.keyPress(KEYS.TAB);
        await session.waitForText('Tab to return to chat');

        // Input should NOT be visible (preserved but hidden)
        const screen = await session.getScreen();
        expect(screen).not.toContain('preserved message');

        // Switch back to chat
        await session.keyPress(KEYS.TAB);

        // Input should be visible again
        expect(await session.hasText('preserved message')).toBe(true);
      });
    }, 10000);
  });

  describe('Help System', () => {
    it('should show help overlay with ? key', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        await session.type('?');

        await session.waitForText('Keyboard Shortcuts');
        expect(await session.hasText('Tab')).toBe(true);
        expect(await session.hasText('Ctrl+C')).toBe(true);
        expect(await session.hasText('Y')).toBe(true);
        expect(await session.hasText('N')).toBe(true);
        expect(await session.hasText('E')).toBe(true);
      });
    }, 10000);

    it('should close help with any key', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        await session.type('?');
        await session.waitForText('Keyboard Shortcuts');

        await session.keyPress(KEYS.ENTER);
        await session.sleep(500);

        // Help should be gone - check screen content
        const screen = await session.getScreen();
        expect(screen).not.toContain('Keyboard Shortcuts');
      });
    }, 10000);
  });

  describe('Cross-Tier Validation', () => {
    it('should match Tier 2 mocked component output', async () => {
      await tuiTest(async (session) => {
        await session.start(`node ${CLI_PATH}`);
        await session.waitForText('Welcome');

        // Get the actual rendered output
        const screen = await session.getScreen();

        // Validate key elements that Tier 2 tests check for
        expect(screen).toContain('Welcome');
        expect(screen).toContain('Tab');
        expect(screen).toContain('chipilot');

        // These should be present in both Tier 2 mocks and real app
        const hasYouIndicator = screen.includes('You') || screen.includes('>');
        expect(hasYouIndicator).toBe(true);
      });
    }, 10000);
  });
});
